    host: &dyn V2RuntimeHost,
    tool_ctx: &ToolContext,
    workspace_path: &Path,
    command: &str,
) -> Result<ExecutionResult, DispatchError> {
    let cwd = shell_single_quote(&workspace_path.display().to_string());
    let script = format!("cd {cwd} && {command}");
    let value = host
        .run_deterministic(
            "orbit_tool_call",
            &Value::Null,
            &json!({
                "tool_name": "proc.spawn",
                "args": {
